// NODO COMBINADO: Preparar imagen + Llamar Claude Vision API
const item = $input.first();

// 1. Verificar que llegó la imagen
if (!item.binary || !item.binary.imagen) {
  return [{
    json: {
      content: [{ text: JSON.stringify({
        error: true,
        encabezado: { fecha: '???', mina: '???', guardia: '???', empresa: '???', equipo_codigo: '???', veta: '???', numero_correlativo: '???' },
        horometros: { macro: null, inicial: null, final: null, tipo_combustible: '?' },
        actividades: [],
        operador: { nombre: '???', datos: '', horometro: null },
        observaciones_generales: '',
        fallas: [],
        firmas_presentes: { jefe_guardia_ecm: false, jefe_guardia_volcan: false, tecnico_mantenimiento: false, residente_ecm: false, supervisor_mantenimiento: false },
        tipo_copia: '???',
        confianza_global: 0
      }) }]
    }
  }];
}

// 2. Leer binario como base64
const binaryData = await this.helpers.getBinaryDataBuffer('imagen');
const base64Image = binaryData.toString('base64');
const mimeType = item.binary.imagen.mimeType || 'image/jpeg';

// 3. Prompt para Claude Vision
const prompt = `Eres un sistema experto en extracción de datos de reportes operativos mineros. Analiza esta imagen del "Reporte de Operación de Equipos: SCOOPTRAM" de la minera Volcán.

IMPORTANTE:
- El formato está rotado 90° (landscape). El título está en el borde derecho.
- Los datos están escritos A MANO con bolígrafo, puede haber letra difícil.
- Si no puedes leer un campo con certeza, coloca "???" y agrega confianza baja.
- Las horas están en formato HH:MM (24h).
- Los horómetros son números decimales.
- Los códigos de actividad comunes son: 120, 122, 123, 200, 202, 203, 262, 301, 302, M05, 191, 193.

EXTRAE y devuelve ÚNICAMENTE un JSON válido con esta estructura exacta (sin texto adicional, sin markdown, sin explicaciones):

{
  "encabezado": { "mina": "string", "fecha": "YYYY-MM-DD", "guardia": "DIA|NOCHE", "empresa": "string", "equipo_codigo": "string", "veta": "string", "numero_correlativo": "string" },
  "horometros": { "macro": "number|null", "inicial": "number", "final": "number", "tipo_combustible": "D|E" },
  "actividades": [{ "fila": "int", "hora_inicio": "HH:MM", "hora_final": "HH:MM", "cod_actividad": "string", "veta": "string", "origen_zona": "string", "origen_nivel": "string", "origen_labor": "string", "labor_ref": "string", "destino_zona": "string", "destino_nivel": "string", "destino_labor": "string", "material_md": "string", "num_viajes": "int|null", "dist_promedio": "number|null", "cod_equipo_transporte": "string", "num_cucharas": "int|null", "observaciones": "string", "confianza": "float 0-1" }],
  "operador": { "nombre": "string", "datos": "string", "horometro": "number|null" },
  "observaciones_generales": "string",
  "fallas": [{ "no": "int", "nombre_sobrestante": "string", "sistema": "string", "sintoma": "string", "causa": "string", "horometro": "number|null" }],
  "firmas_presentes": { "jefe_guardia_ecm": "bool", "jefe_guardia_volcan": "bool", "tecnico_mantenimiento": "bool", "residente_ecm": "bool", "supervisor_mantenimiento": "bool" },
  "tipo_copia": "ORIGINAL|MANTENIMIENTO|CONTROL OPERATIVO",
  "confianza_global": "float 0-1"
}

Solo incluye filas de actividades que tengan datos escritos (ignora filas vacías).
Para campos ilegibles usa "???" en strings y null en números.
El campo "confianza" por fila indica qué tan seguro estás de la lectura (0.0 a 1.0).`;

// 4. Construir body del request
const requestBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  messages: [{
    role: 'user',
    content: [
      {
        type: 'image',
        source: {
          type: 'base64',
          media_type: mimeType,
          data: base64Image
        }
      },
      {
        type: 'text',
        text: prompt
      }
    ]
  }]
};

// 5. Llamar a Claude API usando httpRequest helper de n8n
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': 'REEMPLAZAR_CON_TU_API_KEY',
    'anthropic-version': '2023-06-01',
    'Content-Type': 'application/json'
  },
  body: requestBody,
  json: true,
  timeout: 120000
});

return [{ json: response }];

// Parsear respuesta JSON de Claude
const item = $input.first();
let responseText = '';

try {
  responseText = item.json.content[0].text;
} catch (e) {
  return [{
    json: {
      error: true,
      message: 'No se pudo obtener texto de respuesta de Claude',
      raw_response: JSON.stringify(item.json)
    }
  }];
}

// Limpiar posibles backticks de markdown
const cleanJson = responseText
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch (e) {
  return [{
    json: {
      error: true,
      message: 'Error parseando JSON de Claude: ' + e.message,
      raw_response: responseText
    }
  }];
}

return [{ json: { ...parsed, error: false } }];

// Validación de datos
const data = $input.first().json;
const errores = [];
const advertencias = [];

if (data.error) {
  return [{ json: { ...data, validacion_ok: false, validacion: { errores: [data.message], advertencias: [] } } }];
}

// 1. Fecha válida
if (!data.encabezado || !data.encabezado.fecha || data.encabezado.fecha === '???') {
  errores.push('Fecha no legible');
}

// 2. Horómetros
const hi = data.horometros ? data.horometros.inicial : null;
const hf = data.horometros ? data.horometros.final : null;
if (hi !== null && hf !== null && hi !== undefined && hf !== undefined) {
  if (hf < hi) {
    errores.push(`Horómetro final (${hf}) menor que inicial (${hi})`);
  }
  const diff = Math.round((hf - hi) * 100) / 100;
  if (diff > 24) {
    advertencias.push(`Diferencia de horómetro (${diff}) mayor a 24h`);
  }
}

// 3. Validar actividades
const actividades = data.actividades || [];
if (actividades.length === 0) {
  errores.push('No se extrajeron actividades del reporte');
}

const codigosValidos = ['120','122','123','200','202','203','262','301','302','M05','191','193','HO5'];

for (const act of actividades) {
  if (act.hora_inicio && act.hora_final) {
    const [hiH, hiM] = act.hora_inicio.split(':').map(Number);
    const [hfH, hfM] = act.hora_final.split(':').map(Number);
    const inicioMin = hiH * 60 + hiM;
    const finalMin = hfH * 60 + hfM;
    if (finalMin <= inicioMin && inicioMin < 720) {
      advertencias.push(`Fila ${act.fila}: Hora final <= hora inicio`);
    }
  }
  if (act.cod_actividad && !codigosValidos.includes(act.cod_actividad) && act.cod_actividad !== '???') {
    advertencias.push(`Fila ${act.fila}: Código actividad ${act.cod_actividad} no reconocido`);
  }
  if (act.confianza !== undefined && act.confianza !== null && act.confianza < 0.7) {
    advertencias.push(`Fila ${act.fila}: Baja confianza de lectura (${(act.confianza * 100).toFixed(0)}%)`);
  }
}

// 4. Confianza global
if (data.confianza_global !== undefined && data.confianza_global < 0.6) {
  errores.push('Confianza global muy baja, considerar reprocesar');
}

// 5. Operador
if (!data.operador || !data.operador.nombre || data.operador.nombre === '???') {
  advertencias.push('Nombre de operador no legible');
}

data.validacion = { errores, advertencias };
data.validacion_ok = errores.length === 0;

return [{ json: data }];

// Preparar fila para hoja encabezados
const data = $input.first().json;
const hi = data.horometros ? data.horometros.inicial : null;
const hf = data.horometros ? data.horometros.final : null;
const diff = (hi !== null && hf !== null) ? Math.round((hf - hi) * 100) / 100 : null;

return [{
  json: {
    fecha_procesamiento: new Date().toISOString(),
    numero_correlativo: data.encabezado ? data.encabezado.numero_correlativo : '',
    fecha: data.encabezado ? data.encabezado.fecha : '',
    guardia: data.encabezado ? data.encabezado.guardia : '',
    empresa: data.encabezado ? data.encabezado.empresa : '',
    equipo_codigo: data.encabezado ? data.encabezado.equipo_codigo : '',
    veta: data.encabezado ? data.encabezado.veta : '',
    horometro_inicial: hi,
    horometro_final: hf,
    horometro_diferencia: diff,
    tipo_combustible: data.horometros ? data.horometros.tipo_combustible : '',
    nombre_operador: data.operador ? data.operador.nombre : '',
    observaciones_generales: data.observaciones_generales || '',
    tipo_copia: data.tipo_copia || '',
    confianza_global: data.confianza_global || 0,
    num_actividades: data.actividades ? data.actividades.length : 0,
    num_errores: data.validacion ? data.validacion.errores.length : 0,
    num_advertencias: data.validacion ? data.validacion.advertencias.length : 0,
    _datos_completos: data
  }
}];

// Expandir actividades como items individuales
const data = $input.first().json._datos_completos || $input.first().json;
const actividades = data.actividades || [];
const correlativo = data.encabezado ? data.encabezado.numero_correlativo : '';
const fecha = data.encabezado ? data.encabezado.fecha : '';

return actividades.map(act => ({
  json: {
    numero_correlativo: correlativo,
    fecha: fecha,
    fila: act.fila,
    hora_inicio: act.hora_inicio,
    hora_final: act.hora_final,
    cod_actividad: act.cod_actividad,
    veta: act.veta,
    origen_zona: act.origen_zona,
    origen_nivel: act.origen_nivel,
    origen_labor: act.origen_labor,
    labor_ref: act.labor_ref,
    destino_zona: act.destino_zona,
    destino_nivel: act.destino_nivel,
    destino_labor: act.destino_labor,
    material_md: act.material_md,
    num_viajes: act.num_viajes,
    dist_promedio: act.dist_promedio,
    cod_equipo_transporte: act.cod_equipo_transporte,
    num_cucharas: act.num_cucharas,
    observaciones: act.observaciones,
    confianza: act.confianza
  }
}));

// Expandir fallas como items individuales
const data = $input.first().json._datos_completos || $input.first().json;
const fallas = data.fallas || [];
const correlativo = data.encabezado ? data.encabezado.numero_correlativo : '';
const fecha = data.encabezado ? data.encabezado.fecha : '';

if (fallas.length === 0) {
  return [];
}

return fallas.map(f => ({
  json: {
    numero_correlativo: correlativo,
    fecha: fecha,
    no_falla: f.no,
    nombre_sobrestante: f.nombre_sobrestante,
    sistema: f.sistema,
    sintoma: f.sintoma,
    causa: f.causa,
    horometro: f.horometro
  }
}));

// Respuesta exitosa al webhook
const data = $input.first().json;
const datosCompletos = data._datos_completos || data;

return [{
  json: {
    status: 'success',
    numero_correlativo: datosCompletos.encabezado ? datosCompletos.encabezado.numero_correlativo : '',
    actividades_procesadas: datosCompletos.actividades ? datosCompletos.actividades.length : 0,
    advertencias: datosCompletos.validacion ? datosCompletos.validacion.advertencias : [],
    confianza_global: datosCompletos.confianza_global || 0,
    ...datosCompletos
  }
}];

// Manejo de errores
const data = $input.first().json;

return [{
  json: {
    status: 'error',
    errores: data.validacion ? data.validacion.errores : [data.message || 'Error desconocido'],
    advertencias: data.validacion ? data.validacion.advertencias : [],
    sugerencia: 'Tomar nueva foto con mejor iluminación',
    confianza_global: data.confianza_global || 0,
    ...data
  }
}];
